// Pull the AI output and original webhook data
const rawOutput = $('AI — Identify Document Type').item.json.output || '';
const webhookBody = $('Webhook — Receive Document').item.json.body || {};
const extractedText = $('AI — Identify Document Type').item.json.output ? $input.item.json.output : '';

// Strip markdown fences if the model wrapped it anyway
let cleaned = rawOutput.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();

let classification;
try {
  classification = JSON.parse(cleaned);
} catch (e) {
  // Attempt to extract JSON object from within the string
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) {
    classification = JSON.parse(match[0]);
  } else {
    throw new Error('Could not parse classification JSON from AI output: ' + cleaned.substring(0, 200));
  }
}

// Build a readable placeholder list for the template prompt
const fieldList = (classification.fields || []).map(f => f.placeholder + ' — ' + f.description).join('\n');

return [{
  json: {
    documentType: classification.documentType || 'Document',
    documentTypeSlug: classification.documentTypeSlug || 'document',
    documentDescription: classification.description || '',
    fields: classification.fields || [],
    fieldList: fieldList,
    fileName: webhookBody.fileName || 'unknown',
    additionalContext: webhookBody.additionalContext || ''
  }
}];

const rawAiOutput = $('AI — Generate Template').item.json.output || '';
const meta = $('Code — Parse Classification').item.json;

let cleanOutput = rawAiOutput;

// Strip markdown code fences
cleanOutput = cleanOutput.replace(/```[a-z]*\n?/gi, '');
cleanOutput = cleanOutput.replace(/```\s*$/g, '');

// Strip any preamble headers the model might add
cleanOutput = cleanOutput.replace(/^(TEMPLATE:|OUTPUT:|DOCUMENT TEMPLATE:)\s*\n/gim, '');
cleanOutput = cleanOutput.replace(/^\*\*(TEMPLATE|OUTPUT|RESULT):\*\*\s*\n/gim, '');

// Strip placeholder/field lists if the model included them before the doc
cleanOutput = cleanOutput.replace(/^[\s\S]*?(?=^[A-Z\[\(])/m, '');

// Remove markdown bold
cleanOutput = cleanOutput.replace(/\*\*([^*]+)\*\*/g, '$1');

// Normalize whitespace
cleanOutput = cleanOutput.replace(/\n{3,}/g, '\n\n').trim();

// Build filename
const timestamp = new Date().toISOString().split('T')[0];
const filename = meta.documentTypeSlug + '_template_' + timestamp;

// Build HTML for Gotenberg
const htmlBody = cleanOutput.replace(/\n/g, '<br>');

const htmlContent = '<!DOCTYPE html>\n<html>\n<head>\n  <meta charset="UTF-8">\n  <style>\n    @page { size: letter; margin: 1in; }\n    body { font-family: Arial, Helvetica, sans-serif; font-size: 11pt; line-height: 1.6; margin: 0; padding: 0; color: #222; }\n    br { display: block; margin: 0; }\n  </style>\n</head>\n<body>\n  ' + htmlBody + '\n</body>\n</html>';

const binaryData = Buffer.from(htmlContent, 'utf-8');

return [{
  json: {
    filename: filename,
    documentType: meta.documentType,
    documentTypeSlug: meta.documentTypeSlug,
    documentDescription: meta.documentDescription,
    fields: meta.fields,
    originalFileName: meta.fileName,
    createdDate: timestamp,
    htmlContent: htmlContent,
    originalLength: rawAiOutput.length,
    cleanedLength: cleanOutput.length
  },
  binary: {
    data: {
      data: binaryData.toString('base64'),
      mimeType: 'text/html',
      fileName: 'index.html'
    }
  }
}];

